/* =============================================
   LUFFY DARKEN THEME - LIGHT BLUE ACCENTS
   Massive CSS for 100% perfection
   ============================================= */

/* ---- 1. GLOBAL BACKGROUND (only in chat area) ---- */
body, .appMount-3, .theme-dark, #app-mount {
  background-color: #0E0E0F !important;
  background-image: url('https://raw.githubusercontent.com/a67680293-sys/Revenge-theme/main/66ff8b8e6fe1d286aa44bab423133458.jpg') !important;
  background-size: cover !important;
  background-position: center center !important;
  background-attachment: fixed !important;
  background-repeat: no-repeat !important;
}

/* ---- 2. CHAT & DMS: transparent to show image ---- */
.chat, [class*="chatContent"], [class*="messagesWrapper"],
[class*="scrollerInner"], [class*="channelTextArea"],
[class*="chat"] > div, [class*="messages"] > div, [class*="scroller"] {
  background-color: transparent !important;
}

/* ---- 3. ALL OTHER CONTAINERS: solid dark glass ---- */
[class*="guilds"], [class*="channels"], [class*="members"],
[class*="panels"], [class*="sidebar"], [class*="container"],
[class*="modal"], [class*="popout"], [class*="tooltip"],
[class*="userPopout"], [class*="menu"], [class*="header"],
[class*="titleBar"], [class*="wrapper"], [class*="privateChannels"],
[class*="channelList"], [class*="layer"]:not(.chat layer),
[class*="backgroundPrimary"], [class*="backgroundSecondary"] {
  background-color: rgba(14, 14, 15, 0.88) !important;
  backdrop-filter: blur(2px);
}

/* ---- 4. TEXT & MESSAGES: super bright ---- */
span, div, .text, .channelName, .name, .username, .messageContent,
[class*="message"], [class*="channel"], [class*="member"],
[class*="header"], [class*="title"], [class*="name"],
[class*="role"], [class*="status"], [class*="activity"],
[class*="chat"] *, [class*="message"] * {
  color: #dbdee1 !important;
  text-shadow: 0 0 1px rgba(219, 222, 225, 0.2);
}

/* ---- 5. BLUE INTERACTIVE ELEMENTS (Buttons, Icons, Links, Hashes) ---- */
/* Channel name hashes (#) and channel icons */
[class*="icon"], [class*="icon"], .icon, [class*="channelIcon"],
[class*="prefix"]::before, [class*="hash"] {
  color: #3a86ff !important;
}

/* All buttons */
[class*="button"], [class*="clickable"], [class*="select"],
[class*="option"], [class*="item"], [class*="icon"],
[class*="action"], [class*="control"] {
  transition: all 0.15s ease;
}
[class*="button"]:hover, [class*="clickable"]:hover,
[class*="option"]:hover, [class*="item"]:hover {
  filter: drop-shadow(0 0 3px #3a86ff);
}

/* Primary buttons (solid blue) */
[class*="buttonPrimary"], [class*="brand"], [class*="positive"],
[class*="lookFilled"][class*="colorBrand"] {
  background-color: #3a86ff !important;
  border-color: #3a86ff !important;
}
[class*="buttonPrimary"]:hover, [class*="brand"]:hover, [class*="positive"]:hover {
  background-color: #0050b3 !important;
}

/* Secondary/outline buttons */
[class*="buttonSecondary"], [class*="outline"],
[class*="lookOutlined"][class*="colorBrand"] {
  background-color: rgba(14, 14, 15, 0.7) !important;
  border-color: #3a86ff !important;
  color: #3a86ff !important;
}
[class*="buttonSecondary"]:hover, [class*="outline"]:hover {
  background-color: rgba(58, 134, 255, 0.2) !important;
}

/* Danger buttons (keep red) */
[class*="buttonDanger"], [class*="lookFilled"][class*="colorDanger"] {
  background-color: #f83838 !important;
  border-color: #f83838 !important;
}

/* ---- 6. MENTIONS & PINGS (keep gold for contrast) ---- */
.mention, .mention.interactive, [class*="mention"] {
  background: linear-gradient(135deg, rgba(255,184,0,0.85), rgba(255,100,0,0.6)) !important;
  color: #FFFFFF !important;
  border-radius: 8px;
  box-shadow: 0 0 8px #FFB800;
  font-weight: bold;
  padding: 2px 6px;
}
.mention:hover {
  background: rgba(255,184,0,0.95) !important;
  box-shadow: 0 0 12px #FFB800;
}

/* ---- 7. MESSAGE HIGHLIGHTS & HOVER (blue tint) ---- */
[class*="message"]:hover, [class*="selected"],
[class*="messageGroupWrapper"]:hover {
  background-color: rgba(58, 134, 255, 0.1) !important;
}

/* ---- 8. CHAT INPUT AREA ---- */
.textArea-2, .chatInput-3, [class*="channelTextArea"],
[class*="slateContainer"] {
  background-color: rgba(14, 14, 15, 0.95) !important;
  border: 1px solid rgba(58, 134, 255, 0.4) !important;
  border-radius: 12px;
}

/* ---- 9. SCROLLBARS (blue) ---- */
::-webkit-scrollbar-thumb {
  background: rgba(58, 134, 255, 0.6) !important;
  border-radius: 10px;
}
::-webkit-scrollbar-track {
  background: rgba(14, 14, 15, 0.6) !important;
}
::-webkit-scrollbar-corner {
  background: rgba(14, 14, 15, 0.6) !important;
}

/* ---- 10. GUILD/SERVER ICONS (blue glow on hover) ---- */
[class*="guildIcon"], [class*="wrapper"], [class*="listItem"] {
  transition: transform 0.2s, filter 0.2s;
}
[class*="guildIcon"]:hover, [class*="wrapper"]:hover {
  transform: scale(1.05);
  filter: drop-shadow(0 0 6px #3a86ff);
}

/* ---- 11. MODALS, POPOUTS, TOOLTIPS (glass with blue border) ---- */
.modal, .popout, .tooltip, .userPopout, [class*="popover"],
[class*="menu"], [class*="dropdown"], [class*="options"],
[class*="layerContainer"] [class*="container"] {
  background-color: rgba(14, 14, 15, 0.96) !important;
  backdrop-filter: blur(6px);
  border: 1px solid rgba(58, 134, 255, 0.3);
  border-radius: 8px;
}

/* ---- 12. INPUT FIELDS, TEXTAREA, SELECTS ---- */
input, textarea, select, [class*="input"], [class*="field"],
[class*="textArea"]:not([class*="channelTextArea"]) {
  background-color: rgba(14, 14, 15, 0.9) !important;
  color: #dbdee1 !important;
  border-color: rgba(58, 134, 255, 0.5) !important;
  border-radius: 6px;
}
input:focus, textarea:focus, select:focus {
  border-color: #3a86ff !important;
  box-shadow: 0 0 4px #3a86ff;
}

/* ---- 13. LINKS ---- */
a, [class*="link"], [class*="anchor"] {
  color: #3a86ff !important;
  text-decoration: none;
}
a:hover, [class*="link"]:hover {
  color: #7cb5ff !important;
  text-decoration: underline;
}

/* ---- 14. CHANNEL LIST SPECIFICS (blue category names, hash icons) ---- */
[class*="channelName"], [class*="categoryName"],
[class*="nameDefaultText"] {
  color: #dbdee1 !important;
}
[class*="channelName"]:hover, [class*="categoryName"]:hover {
  color: #3a86ff !important;
}
[class*="icon"][class*="hash"], [class*="prefix"] {
  color: #3a86ff !important;
}

/* ---- 15. MEMBER LIST & ACTIVITY ---- */
[class*="member"]:hover, [class*="activity"] {
  background-color: rgba(58, 134, 255, 0.1) !important;
}
[class*="avatar"]:hover {
  filter: drop-shadow(0 0 4px #3a86ff);
}

/* ---- 16. STATUS INDICATORS (blue online) ---- */
[class*="statusOnline"], [class*="statusStreaming"] {
  background-color: #3a86ff !important;
}
[class*="statusIdle"] {
  background-color: #faeb64 !important;
}
[class*="statusDND"] {
  background-color: #f83838 !important;
}
[class*="statusOffline"] {
  background-color: #AAAAAA !important;
}

/* ---- 17. REACTION BUTTONS ---- */
[class*="reaction"], [class*="reactionInner"] {
  background-color: rgba(14, 14, 15, 0.7) !important;
  border-color: rgba(58, 134, 255, 0.3) !important;
}
[class*="reaction"]:hover {
  background-color: rgba(58, 134, 255, 0.2) !important;
  border-color: #3a86ff !important;
}

/* ---- 18. CONTEXT MENUS ---- */
[class*="contextMenu"] [class*="item"]:hover {
  background-color: rgba(58, 134, 255, 0.2) !important;
}
[class*="contextMenu"] [class*="dangerItem"]:hover {
  background-color: rgba(248, 56, 56, 0.2) !important;
}

/* ---- 19. DARKEN ANY REMAINING OPAQUE AREAS (safety) ---- */
[class*="background"], [class*="layer"], [class*="container"]:not([class*="chat"]):not([class*="message"]) {
  background-color: rgba(14, 14, 15, 0.85) !important;
}

/* ---- 20. EMBEDS & ATTACHMENTS (keep them readable) ---- */
[class*="embed"], [class*="attachment"] {
  background-color: rgba(14, 14, 15, 0.9) !important;
  border-left: 4px solid #3a86ff !important;
  border-radius: 8px;
}
[class*="embedTitle"] {
  color: #3a86ff !important;
}

/* ---- 21. TOAST NOTIFICATIONS (snackbar) ---- */
[class*="toast"], [class*="snackbar"] {
  background-color: rgba(14, 14, 15, 0.95) !important;
  border: 1px solid #3a86ff;
}

/* ---- 22. VOICE CHANNEL CONTROLS (blue) ---- */
[class*="voiceUser"]:hover, [class*="voiceChannel"]:hover {
  background-color: rgba(58, 134, 255, 0.15) !important;
}
[class*="voiceState"] [class*="button"]:hover {
  color: #3a86ff !important;
}

/* ---- 23. SPOILER TAGS ---- */
[class*="spoilerHidden"] {
  background-color: rgba(14, 14, 15, 0.9) !important;
}
[class*="spoilerRevealed"] {
  background-color: rgba(40, 40, 45, 0.8) !important;
}

/* ---- 24. MESSAGE ACTION BUTTONS (reply, edit, etc) ---- */
[class*="messageActions"] [class*="button"] {
  background-color: rgba(14, 14, 15, 0.8) !important;
  border-radius: 4px;
}
[class*="messageActions"] [class*="button"]:hover {
  background-color: #3a86ff !important;
}

/* ---- 25. CALL / VIDEO CONTROLS ---- */
[class*="callContainer"] [class*="button"]:hover {
  background-color: #3a86ff !important;
}

/* ---- 26. DISCOVERY & SHOP SECTIONS ---- */
[class*="guildsDiscovery"], [class*="shop"] {
  background-color: rgba(14, 14, 15, 0.9) !important;
}

/* ---- 27. FINAL SAFETY: FORCE CHAT BACKGROUND TRANSPARENT ---- */
[class*="chat"] [class*="background"],
[class*="messagesWrapper"] [class*="background"],
[class*="scroller"] [class*="background"] {
  background-color: transparent !important;
}

/* ---- 28. MICROPHONE & SPEAKER BUTTONS IN VOICE ---- */
[class*="voiceButtons"] [class*="button"]:hover {
  background-color: #3a86ff !important;
  color: white !important;
}

/* ---- 29. GAME ACTIVITY CARDS ---- */
[class*="gameActivity"] {
  background-color: rgba(14, 14, 15, 0.85) !important;
  border-left: 3px solid #3a86ff;
}

/* ---- 30. TYPING INDICATOR (blue pulse) ---- */
[class*="typing"] {
  color: #3a86ff !important;
}
[class*="typingDots"] {
  background-color: #3a86ff !important;
}

/* ---- 31. PERFECT SCROLLBARS FOR EVERY ELEMENT ---- */
* {
  scrollbar-color: #3a86ff rgba(14, 14, 15, 0.6);
}

/* ---- 32. BADGES (unread, mentions, etc) ---- */
[class*="badge"], [class*="unread"], [class*="mentionBadge"] {
  background-color: #3a86ff !important;
  color: white !important;
}
[class*="unread"] {
  background-color: #3a86ff !important;
}

/* ---- 33. SEARCH BAR ---- */
[class*="searchBar"] {
  background-color: rgba(14, 14, 15, 0.9) !important;
  border: 1px solid rgba(58, 134, 255, 0.5) !important;
}
[class*="searchBar"]:focus-within {
  border-color: #3a86ff !important;
}

/* ---- 34. USER SETTINGS MODAL ---- */
[class*="standardSidebarView"] {
  background-color: rgba(14, 14, 15, 0.95) !important;
}
[class*="settingsTab"]:hover {
  background-color: rgba(58, 134, 255, 0.15) !important;
}
[class*="settingsTab"][class*="selected"] {
  background-color: #3a86ff !important;
  color: white !important;
}

/* ---- 35. NOTIFICATION POPUPS (toast) ---- */
[class*="notification"] {
  background-color: rgba(14, 14, 15, 0.95) !important;
  border-left: 4px solid #3a86ff;
}

/* ---- 36. SELECT MENU DROPDOWN ---- */
[class*="select"] [class*="option"]:hover {
  background-color: rgba(58, 134, 255, 0.2) !important;
}
[class*="selectedValue"] {
  color: #3a86ff !important;
}

/* ---- 37. DATE SEPARATORS IN CHAT ---- */
[class*="divider"] span {
  background-color: rgba(14, 14, 15, 0.7) !important;
  color: #3a86ff !important;
}

/* ---- 38. LOADING SPINNERS ---- */
[class*="spinner"] circle {
  stroke: #3a86ff !important;
}

/* ---- 39. INVITE BUTTON ---- */
[class*="inviteButton"] {
  background-color: #3a86ff !important;
}
[class*="inviteButton"]:hover {
  background-color: #0050b3 !important;
}

/* ---- 40. FINAL OVERRIDE: ENSURE NO INVISIBLE ELEMENTS ---- */
* {
  opacity: 1 !important;
}
